export default {
  plugins: {
    tailwindcss: {},
    autoprefixer: {},
    'postcss-nested': {}
  }
}

import React from 'react'
import GameUI from './components/GameUI'

function App() {
  return <GameUI />
}

export default App

import React, { useEffect, useRef } from 'react'
import { useGameStore } from '../store'

interface FloatingNumberProps {
  id: number
  value: number
  x: number
  y: number
}

function FloatingNumber() {
  const [floatingNumbers, setFloatingNumbers] = React.useState<FloatingNumberProps[]>([])
  const idCounter = useRef(0)
  const incrementPoop = useGameStore((state) => state.incrementPoop)

  // Handle click events to spawn floating numbers
  useEffect(() => {
    const handleGlobalClick = (e: MouseEvent) => {
      // Only spawn if clicking on the toilet button area
      const target = e.target as HTMLElement
      if (target.closest('button')) {
        const id = idCounter.current++
        const value = useGameStore.getState().clickPower

        setFloatingNumbers(prev => [
          ...prev,
          { id, value, x: e.clientX, y: e.clientY }
        ])

        // Remove after animation
        setTimeout(() => {
          setFloatingNumbers(prev => prev.filter(item => item.id !== id))
        }, 2000)
      }
    }

    window.addEventListener('click', handleGlobalClick)
    return () => window.removeEventListener('click', handleGlobalClick)
  }, [])

  return (
    <div className="fixed inset-0 pointer-events-none z-50">
      {floatingNumbers.map(number => (
        <div
          key={number.id}
          className="absolute text-2xl font-bold text-yellow-400 drop-shadow-md animate-float-up"
          style={{
            left: `${number.x}px`,
            top: `${number.y - 50}px`,
            transformOrigin: 'center',
            transform: 'translateX(-50%) scale-150'
          }}
        >
          +{number.value}
        </div>
      ))}
    </div>
  )
}

export default FloatingNumber

import React from 'react'
import { formatCompactNumber } from '@/utils/formatter'

interface StatDisplayProps {
  label: string
  value: number
}

function StatDisplay({ label, value }: StatDisplayProps) {
  return (
