import React from 'react'
import { useGameStore } from '../store'
import useGameLogic from '../hooks/useGameLogic'

function ToiletButton() {
  const { handleToiletClick } = useGameLogic()
  const [isClicking, setIsClicking] = React.useState<'idle' | 'pressing' | 'releasing'>('idle')

  const handleClick = (e: React.MouseEvent<HTMLButtonElement>) => {
    // Trigger animation
    setIsClicking('pressing')

    // Handle game logic
    handleToiletClick(e)

    // Release after animation completes
    setTimeout(() => {
      setIsClicking('releasing')
      setTimeout(() => setIsClicking('idle'), 100)
    }, 100)
  }

  return (
    <button
      onClick={handleClick}
      className="relative group focus:outline-none"
      aria-label="Flush and collect poop"
    >
      {/* Glow effect */}
      <div className="absolute inset-0 rounded-full bg-purple-500/30 blur-xl transition-all duration-300 group-hover:scale-125 group-hover:bg-purple-400/40" />

