    event: 'research_complete', project_id: projectId,
    data: { libraries_fetched: toFetch, doc_count: docs.length, doc_chars: docs.reduce((s,d) => s+d.length, 0), errors: errors.length ? errors : undefined }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: $json }];

// Build Check: run npm install + vite build, store errors for reviewer/fixer
const http = require('http');
const staticData = $getWorkflowStaticData('global');
const projectId = $('Extract Input').first().json.project_id || 'unknown';

let buildResult = { success: true, output: '' };

try {
  const body = '';
  const result = await new Promise((resolve, reject) => {
    const req = http.request({
      hostname: 'file-api', port: 3456, method: 'POST',
      path: `/projects/${projectId}/build-check`,
      headers: {
        'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''),
        'Content-Type': 'application/json',
        'Content-Length': 0
      }
    }, res => {
      let data = '';
      res.on('data', c => data += c);
      res.on('end', () => { try { resolve(JSON.parse(data)); } catch(e) { resolve({ success: false, error: data }); } });
    });
    req.on('error', e => resolve({ success: false, error: e.message }));
    req.setTimeout(180000, () => { req.destroy(); resolve({ success: false, error: 'Build check timed out' }); });
    req.end();
  });
  buildResult = result;
} catch(e) {
  buildResult = { success: false, error: e.message };
}

// Store build result for reviewer
staticData._buildResult = buildResult;

// If build passed, start preview, screenshot, stop preview
staticData._screenshot_b64 = null;
if (buildResult.success) {
  try {
    // Start preview
    const startBody = '';
    await new Promise((resolve, reject) => {
      const req = http.request({
        hostname: 'file-api', port: 3456, method: 'POST',
        path: '/projects/' + projectId + '/preview/start',
        headers: { 'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''), 'Content-Type': 'application/json', 'Content-Length': 0 }
      }, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => resolve(d)); });
      req.on('error', reject);
      req.setTimeout(120000, () => { req.destroy(); reject(new Error('timeout')); });
      req.end();
    });

    // Screenshot via Playwright
    const scrapeBody = JSON.stringify({ url: 'http://localhost:4000' });
    const scrapeResult = await new Promise((resolve, reject) => {
      const req = http.request({
        hostname: 'file-api', port: 3456, method: 'POST', path: '/scrape',
        headers: { 'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''), 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(scrapeBody) }
      }, res => { let d = ''; res.on('data', c => d += c); res.on('end', () => { try { resolve(JSON.parse(d)); } catch(e) { resolve({}); } }); });
      req.on('error', reject);
      req.setTimeout(30000, () => { req.destroy(); reject(new Error('timeout')); });
      req.write(scrapeBody); req.end();
    });
    staticData._screenshot_b64 = scrapeResult.screenshot_b64 || null;

    // Stop preview
    const stopReq = http.request({
      hostname: 'file-api', port: 3456, method: 'POST',
      path: '/projects/' + projectId + '/preview/stop',
      headers: { 'Authorization': 'Bearer ' + ($env.FILE_API_TOKEN || ''), 'Content-Length': 0 }
    });
    stopReq.on('error', () => {});
    stopReq.end();
  } catch(e) { /* screenshot failed, continue without it */ }
}

// Send callback to Forge
try {
  const cbBody = JSON.stringify({
    event: buildResult.success ? 'build_check_passed' : 'build_check_failed',
    project_id: projectId,
    data: { success: buildResult.success, error: buildResult.error || null, stage: buildResult.stage || null }
  });
  const req = http.request({
    hostname: 'forge', port: 3500, path: '/api/status-callback', method: 'POST',
    headers: { 'Content-Type': 'application/json', 'Accept': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) }
  });
  req.on('error', () => {});
  req.write(cbBody);
  req.end();
} catch(e) {}

return [{ json: $json }];
